// Load a class by string name (dynamic!)
Class<?> cls = Class.forName("com.example.User");

// Create an instance without knowing the class at compile time
Object u = cls.getDeclaredConstructor().newInstance();

// Call a method by string name
Method m = cls.getMethod("setName", String.class);
m.invoke(u, "Ada");

// Read a private field — usually blocked
Field f = cls.getDeclaredField("id");
f.setAccessible(true);              // OK, bypass encapsulation (needs permission)
System.out.println(f.get(u));

// List all methods a class declares
for (Method method : cls.getDeclaredMethods()) {
  System.out.println(method.getName() + " -> " + method.getReturnType());
}

// File: ReflectionDemo.java
// Run: javac ReflectionDemo.java && java ReflectionDemo
import java.lang.annotation.*;
import java.lang.reflect.*;
import java.util.*;

public class ReflectionDemo {
  // Our own annotation, at runtime
  @Retention(RetentionPolicy.RUNTIME) @Target(ElementType.FIELD)
  @interface Inject { }

  // Two 'services' — no configuration files, no constructors
  static class Logger { void log(String s) { System.out.println("[log] " + s); } }
  static class Api    { void call()        { System.out.println("[api] called"); } }

  // A consumer — depends on Logger and Api via annotation
  static class OrderService {
    @Inject Logger log;
    @Inject Api    api;

    void placeOrder() {
      log.log("placing order");
      api.call();
    }
  }

  // Our tiny DI container
  static Map<Class<?>, Object> beans = new HashMap<>();

  static <T> void register(Class<T> cls) throws Exception {
    beans.put(cls, cls.getDeclaredConstructor().newInstance());
  }

  static <T> T get(Class<T> cls) throws Exception {
    Object bean = beans.get(cls);
    if (bean == null) {
      bean = cls.getDeclaredConstructor().newInstance();
      beans.put(cls, bean);
    }

    // Inject dependencies marked with @Inject
    for (Field f : cls.getDeclaredFields()) {
      if (f.isAnnotationPresent(Inject.class)) {
        f.setAccessible(true);
        f.set(bean, get(f.getType()));    // recursive resolve
      }
    }
    return cls.cast(bean);
  }

  public static void main(String[] args) throws Exception {
    register(Logger.class);
    register(Api.class);

    OrderService svc = get(OrderService.class);   // NEVER called `new OrderService()`
    svc.placeOrder();                             // logger + api ALREADY injected!
  }
}

// Output:
//   [log] placing order
//   [api] called
//
// We built the CORE of Spring — annotation-driven DI — in 40 lines.
// Real Spring is far more sophisticated, but the mechanism is the same.
